1	import { useState } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { useCreateMarket } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	
6	interface OutcomeInput {
7	  id: string;
8	  name: string;
9	}
10	
11	export function CreateMarketForm() {
12	  const navigate = useNavigate();
13	  const { session } = useSession();
14	  const mutation = useCreateMarket();
15	
16	  const [title, setTitle] = useState("");
17	  const [description, setDescription] = useState("");
18	  const [expiresAt, setExpiresAt] = useState("");
19	  const [liquidity, setLiquidity] = useState("10000");
20	  const [outcomes, setOutcomes] = useState<OutcomeInput[]>([
21	    { id: "yes", name: "Yes" },
22	    { id: "no", name: "No" },
23	  ]);
24	
25	  const addOutcome = () => {
26	    const n = outcomes.length + 1;
27	    setOutcomes([...outcomes, { id: `o${n}`, name: `Option ${n}` }]);
28	  };
29	
30	  const removeOutcome = (idx: number) => {
31	    if (outcomes.length <= 2) return;
32	    setOutcomes(outcomes.filter((_, i) => i !== idx));
33	  };
34	
35	  const updateOutcome = (idx: number, field: keyof OutcomeInput, value: string) => {
36	    const next = [...outcomes];
37	    next[idx] = { ...next[idx]!, [field]: value };
38	    setOutcomes(next);
39	  };
40	
41	  const handleSubmit = (e: React.FormEvent) => {
42	    e.preventDefault();
43	    mutation.mutate(
44	      {
45	        payload: {
46	          title,
47	          description,
48	          outcomes,
49	          expires_at: new Date(expiresAt).toISOString(),
50	          liquidity: Number(liquidity) || 10000,
51	        },
52	        session: session.accountId ? session : undefined,
53	      },
54	      {
55	        onSuccess: (data) => {
56	          navigate(`/markets/${data.market.id}`);
57	        },
58	      },
59	    );
60	  };
61	
62	  const isValid = title.trim().length > 0 && expiresAt.length > 0 && outcomes.every((o) => o.id && o.name);
63	
64	  return (
65	    <div style={{ maxWidth: 600, margin: "0 auto" }}>
66	      <h1 style={{ fontSize: "1.5rem", fontWeight: 600, marginBottom: "var(--space-lg)" }}>
67	        Create Market
68	      </h1>
69	
70	      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "var(--space-md)" }}>
71	        <label style={labelWrapStyle}>
72	          <span style={labelStyle}>Question / Title</span>
73	          <input
74	            type="text"
75	            value={title}
76	            onChange={(e) => setTitle(e.target.value)}
77	            placeholder="Will ETH trade above $5000 by December?"
78	            style={inputStyle}
79	            required
80	          />
81	        </label>
82	
83	        <label style={labelWrapStyle}>
84	          <span style={labelStyle}>Description (optional)</span>
85	          <textarea
86	            value={description}
87	            onChange={(e) => setDescription(e.target.value)}
88	            placeholder="Additional context about resolution criteria..."
89	            rows={3}
90	            style={{ ...inputStyle, resize: "vertical" }}
91	          />
92	        </label>
93	
94	        <div>
95	          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
96	            <span style={labelStyle}>Outcomes (min 2)</span>
97	            <button type="button" onClick={addOutcome} style={addBtnStyle}>+ Add outcome</button>
98	          </div>
99	          <div style={{ display: "grid", gap: "var(--space-sm)" }}>
100	            {outcomes.map((o, idx) => (
101	              <div key={idx} style={{ display: "grid", gridTemplateColumns: "1fr 2fr auto", gap: "var(--space-sm)" }}>
102	                <input
103	                  type="text"
104	                  value={o.id}
105	                  onChange={(e) => updateOutcome(idx, "id", e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, ""))}
106	                  placeholder="id"
107	                  style={{ ...inputStyle, fontFamily: "var(--font-mono)", fontSize: "0.8rem" }}
108	                />
109	                <input
110	                  type="text"
111	                  value={o.name}
112	                  onChange={(e) => updateOutcome(idx, "name", e.target.value)}
113	                  placeholder="Display name"
114	                  style={inputStyle}
115	                />
116	                <button
117	                  type="button"
118	                  onClick={() => removeOutcome(idx)}
119	                  disabled={outcomes.length <= 2}
120	                  style={removeBtnStyle}
121	                >
122	                  ×
123	                </button>
124	              </div>
125	            ))}
126	          </div>
127	        </div>
128	
129	        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "var(--space-md)" }}>
130	          <label style={labelWrapStyle}>
131	            <span style={labelStyle}>Expiry Date</span>
132	            <input
133	              type="datetime-local"
134	              value={expiresAt}
135	              onChange={(e) => setExpiresAt(e.target.value)}
136	              style={inputStyle}
137	              required
138	            />
139	          </label>
140	          <label style={labelWrapStyle}>
141	            <span style={labelStyle}>Initial Liquidity</span>
142	            <input
143	              type="number"
144	              value={liquidity}
145	              onChange={(e) => setLiquidity(e.target.value)}
146	              min={100}
147	              step={1000}
148	              style={inputStyle}
149	            />
150	          </label>
151	        </div>
152	
153	        {/* Preview */}
154	        <div style={previewStyle}>
155	          <span style={{ fontSize: "0.75rem", fontWeight: 600, color: "var(--color-text-muted)" }}>PREVIEW</span>
156	          <div style={{ fontSize: "0.9rem", fontWeight: 600, marginTop: 4 }}>{title || "Untitled market"}</div>
157	          <div style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", marginTop: 2 }}>
158	            {outcomes.length} outcomes · {`1/${outcomes.length}`} uniform prior · ${Number(liquidity).toLocaleString()} liquidity
159	          </div>
160	        </div>
161	
162	        <button
163	          type="submit"
164	          disabled={!isValid || mutation.isPending}
165	          style={{
166	            padding: "10px 20px",
167	            borderRadius: "var(--radius-sm)",
168	            border: "none",
169	            background: isValid ? "var(--color-primary)" : "var(--color-border)",
170	            color: "#fff",
171	            fontWeight: 600,
172	            fontSize: "0.9rem",
173	            cursor: isValid && !mutation.isPending ? "pointer" : "not-allowed",
174	            opacity: mutation.isPending ? 0.6 : 1,
175	          }}
176	        >
177	          {mutation.isPending ? "Creating…" : "Create Market"}
178	        </button>
179	      </form>
180	
181	      {mutation.isError && (
182	        <div style={errorStyle}>
183	          {mutation.error instanceof Error ? mutation.error.message : "Failed to create market"}
184	        </div>
185	      )}
186	    </div>
187	  );
188	}
189	
190	const labelWrapStyle: React.CSSProperties = { display: "block" };
191	const labelStyle: React.CSSProperties = {
192	  display: "block",
193	  fontSize: "0.85rem",
194	  fontWeight: 500,
195	  color: "var(--color-text-muted)",
196	  marginBottom: "var(--space-xs)",
197	};
198	const inputStyle: React.CSSProperties = {
199	  width: "100%",
200	  padding: "8px 12px",
201	  borderRadius: "var(--radius-sm)",
202	  border: "1px solid var(--color-border)",
203	  background: "var(--color-bg)",
204	  color: "var(--color-text)",
205	  fontSize: "0.875rem",
206	};
207	const addBtnStyle: React.CSSProperties = {
208	  padding: "4px 10px",
209	  borderRadius: "var(--radius-sm)",
210	  border: "1px solid var(--color-border)",
211	  background: "transparent",
212	  color: "var(--color-primary)",
213	  fontSize: "0.8rem",
214	  cursor: "pointer",
215	};
216	const removeBtnStyle: React.CSSProperties = {
217	  padding: "4px 8px",
218	  borderRadius: "var(--radius-sm)",
219	  border: "1px solid var(--color-border)",
220	  background: "transparent",
221	  color: "var(--color-danger)",
222	  fontSize: "1rem",
223	  cursor: "pointer",
224	  lineHeight: 1,
225	};
226	const previewStyle: React.CSSProperties = {
227	  padding: "var(--space-md)",
228	  borderRadius: "var(--radius-md)",
229	  border: "1px dashed var(--color-border)",
230	  background: "var(--color-bg)",
231	};
232	const errorStyle: React.CSSProperties = {
233	  marginTop: "var(--space-md)",
234	  padding: "var(--space-sm) var(--space-md)",
235	  borderRadius: "var(--radius-sm)",
236	  background: "rgba(239, 68, 68, 0.1)",
237	  border: "1px solid var(--color-danger)",
238	  fontSize: "0.85rem",
239	  color: "var(--color-danger)",
240	};
